
import type { Metadata } from 'next';
import './globals.css';
import { Header } from '@/components/layout/header';
import { Footer } from '@/components/layout/footer';
import dynamic from 'next/dynamic';

const AnimatedBg = dynamic(() => import('@/components/ui-patterns/animated-bg').then(mod => mod.AnimatedBg), { ssr: false });
const SupportDesk = dynamic(() => import('@/components/layout/SupportDesk').then(mod => mod.SupportDesk), { ssr: false });
const CookieConsent = dynamic(() => import('@/components/cookie-consent'), { ssr: false });

import { Inter, Space_Grotesk } from 'next/font/google';

const inter = Inter({
  subsets: ['latin'],
  variable: '--font-inter',
  display: 'swap',
});

const spaceGrotesk = Space_Grotesk({
  subsets: ['latin'],
  variable: '--font-space-grotesk',
  display: 'swap',
});

export const metadata: Metadata = {
  title: 'CYROTICS TECHNOLOGIES | Technology Infrastructure & Security',
  description:
    'Your trusted partner for integrated infrastructure, security, and smart technology solutions. We specialize in data centers, cybersecurity, and cloud transformation.',
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en" className={`scroll-smooth ${inter.variable} ${spaceGrotesk.variable}`} suppressHydrationWarning>
      <body className="font-body antialiased bg-transparent" suppressHydrationWarning>
        <ThemeProvider
          attribute="class"
          defaultTheme="system"
          enableSystem
          disableTransitionOnChange
        >
          <div className="flex min-h-screen flex-col relative z-0">
            <AnimatedBg />
            <Header />
            <main className="flex-1">{children}</main>
            <Footer />
          </div>
          <SupportDesk />
          <ClientToaster />
          <CookieConsent />
        </ThemeProvider>
      </body>
    </html>
  );
}
